?>

<?php if ( $has_gallery ) : ?>
<section class="gallery">
    <div class="container">

        <div class="gallery__head">
            <img src="<?php echo get_stylesheet_directory_uri(); ?>/assets/images/quote.svg" alt="" class="gallery__icon" aria-hidden="true">
            <?php if ( $gallery_title ) : ?>
                <h2 class="gallery__title"><?php echo esc_html( $gallery_title ); ?></h2>
            <?php endif; ?>
        </div>

        <div class="gallery__grid">
            <?php foreach ( $gallery_rows as $row ) :
                $img = $row['gallery_image'];
                if ( ! $img ) continue;
                $src = is_array( $img ) ? $img['url'] : $img;
                $alt = is_array( $img ) ? ( $img['alt'] ?? '' ) : '';
            ?>
            <div class="gallery__item">
                <a href="<?php echo esc_url( $src ); ?>" class="glightbox" data-gallery="project-gallery" data-description="<?php echo esc_attr( $alt ); ?>">
                    <img src="<?php echo esc_url( $src ); ?>" alt="<?php echo esc_attr( $alt ); ?>" loading="lazy">
                </a>
            </div>
            <?php endforeach; ?>
        </div>

    </div>
</section>
<?php endif; ?>

