<?php
$current_id   = get_the_ID();
$similar_args = [
    'post_type'      => 'projects',
    'posts_per_page' => 6,
    'post_status'    => 'publish',
    'post__not_in'   => [ $current_id ],
    'orderby'        => 'date',
    'order'          => 'DESC',
];

$terms = get_the_terms( $current_id, 'project_category' );
if ( $terms && ! is_wp_error( $terms ) ) {
    $similar_args['tax_query'] = [ [
        'taxonomy' => 'project_category',
        'field'    => 'term_id',
        'terms'    => wp_list_pluck( $terms, 'term_id' ),
    ] ];
}

$similar_query = new WP_Query( $similar_args );

if ( $similar_query->post_count < 2 ) {
    unset( $similar_args['tax_query'] );
    $similar_query = new WP_Query( $similar_args );
}
?>

<?php if ( $similar_query->have_posts() ) : ?>
<section class="similar-projects">
    <div class="container">

        <div class="similar-projects__head">
            <div class="similar-projects__title-wrap">
                <img src="<?php echo get_stylesheet_directory_uri(); ?>/assets/images/quote.svg" alt="" aria-hidden="true">
                <h2 class="similar-projects__title"><?php esc_html_e( 'Our similar projects', 'bury' ); ?></h2>
            </div>
